/*
  Vega Lite Experiment

  The output below shows the average health of golemity as time continues. The
  technical feats in this notebook are import()ing vega, vega-lite, and 
  vega-embed. All that code sits in the second cell.

  To run, click the Run Cell button under each cell. 
*/

(async function(){

  var vegaModule = await import("https://cdn.jsdelivr.net/npm/vega@5");
  var vegaLiteModule = await import("https://cdn.jsdelivr.net/npm/vega-lite@5");
  var vegaEmbedModule = await import("https://cdn.jsdelivr.net/npm/vega-embed@6");

  /*
    Constants
  */
  var Constants = {
    speechBonus: 1.1,
    listenBonus: 1.1,
  }

  function choice(l=[]){
    return l[Math.floor(Math.random() * l.length)];
  }

  function mean(l=[]){
    var sum = 0.0;
    for(var i=0; i<l.length; i++){
      sum += l[i];
    }
    return sum/l.length;
  }

  /*
    Golem
  */
  function Golem(){
    this.health = Math.random();
    this.lapses = 0.0;
  }

  Golem.prototype.speak = function(){
    var impact = (choice([-1, 1]) * Math.random() * Constants.speechBonus);
    this.health += impact;
    return impact;
  }

  Golem.prototype.age = function(){
    this.lapses += 1.0;
    return this.lapses >= 1000.0;
  }

  Golem.prototype.listenTo = function(speech){
    var impact = (Math.random() * speech) + Constants.listenBonus;
    this.health *= impact;
  }

  /*
    Setting
  */
  function Setting(n){
    this.golems = [];
    for(var i=0; i<n; i++){
      this.golems.push(new Golem());
    }
  }

  Setting.prototype.historize = function(fact){
    if(this.history === undefined){
      this.history = {};
    }

    for(var attribute of Object.keys(fact)){
      if(this.history[attribute] === undefined){
        this.history[attribute] = [];
      }

      this.history[attribute].push(fact[attribute]);
    }
  }

  Setting.prototype.round = function(){
    var speaker = choice(this.golems);
    var listener = choice(this.golems);

    var speech = speaker.speak();
    listener.listenTo(speech);

    if(listener.health > 0.075){
      this.golems.push(new Golem());
    }

    // each golem ages
    this.golems.forEach((golem, i) => {
      if(golem.age()){
        this.golems.splice(i, 1);
      }
    })
    var meanHealth = mean(this.golems.map(g => g.health));
    var meanAge = mean(this.golems.map(g => g.lapses));

    this.historize({
      'round'      : this.history.round.length, 
      'mean health': meanHealth,
      'count'      : this.golems.length,
      'mean age'   : meanAge
    });

    return mean(this.golems.map(g => g.health));
  }

  var setting = new Setting(10)

  var chart = document.querySelector('.cell:nth-child(2) > .output')

  vegaEmbed(".cell:first-child>.output", {
    $schema: "https://vega.github.io/schema/vega-lite/v5.json",
    title: "Average Golem Health Over Time",
    data: {name: 'table'},
    width: 550,
    height: 350,
    autosize: {
      resize: true,
      type: "fit",
      contains: "padding"
    },
    legends: [{
      symbolType: "square",
      fill: "color",
      title: "category"
    }],
    layer: [
      {
        mark: "line",
        encoding: {
          x: {
            title: "Iteration", 
            field: "round", 
            type: "ordinal"
          },
          y: {
            title: "Mean Health (/)", 
            field: "mean health", 
            type: "quantitative", 
            scale: {domain: [0, 1]},
            axis: {orient: "left", offset: 20},
          },
          color: {value: "cornflowerblue"}
        }
      },
      {
        mark: "point",
        encoding: {
          x: {
            field: "round",
            type: "ordinal"
          },
          y: {
            title: "Number of Golems (o)",
            field: "count", 
            type: "quantitative", 
            axis: {orient: "right", offset: 20},
          },
          color: {value: "orange"}
        }
      }
    ],
    resolve: {scale: {y: "independent"}}
  }).then(function(res) {
    function newGenerator(){
      var counter = -1;
      var previousY = [0];

      return function(){
        counter++;

        var newVals = previousY.map(function(v, c){
          return {
            'round': counter,
            'mean health': setting.round(),
            'count': setting.golems.length
          }
        });

        previousY = newVals.map(function(v){
          return v['mean health'];
        });

        return newVals;
      };
    }

    var valueGenerator = newGenerator();
    var minimumX = -25;
    window.setInterval(function () {
      minimumX++;
      var changeSet = vega
        .changeset()
        .insert(valueGenerator())
        .remove(function (t) {
          return t['round'] < minimumX;
        });
      res.view.change('table', changeSet).run();
    }, 50);
  });

  setting.historize({round: 0});
})();
